export function isSafeAttachment(
  mimeType: string,
  filename: string
): boolean {
  const mime = mimeType.toLowerCase().trim();
  const name = filename.toLowerCase();

  // Check MIME
  if (!SAFE_MIME_TYPES.has(mime)) {
    // Allow all image/* subtypes
