// ------------------------------------------------------------------
// Message routing (Client → Gateway)
// ------------------------------------------------------------------
function handleClientMessage(ws: WebSocket, raw: string, clientId: string): void {
  const gateway = getWSGateway();
  if (!gateway) return;

  let msg: WSClientMessage;
  try {
    msg = JSON.parse(raw);
