              type: 'MESSAGE_FLAG_CHANGED',
              payload: {
                messageId,
                flags,
                action,
                mailboxId: client.sessionId, // Proxy — should be in payload
              },
              timestamp: Date.now(),
            } satisfies WSServerMessage);
          }
        }
      }
      break;
    }

    default:

