        mailOpts.bcc = message.bcc.map((a) => this.formatAddress(a)).join(', ');
      }

      if (message.replyTo) {
        mailOpts.replyTo = this.formatAddress(message.replyTo);
      }

      if (message.attachments && message.attachments.length > 0) {
