      };

      const info = await this.transport!.sendMail(mailOpts);

      const latency = Date.now() - startTime;
      this.recordSuccess();

      auditLogger.info('Mail sent via SMTP adapter', {
        actor_id: cfg.accountId,
        metadata: {
          from: message.from.email,
          to: message.to.map((a) => a.email),
