    }
  }

  // ----------------------------------------------------------------
  // Verify
  // ----------------------------------------------------------------
  async verify(cfg: IAccountConfig): Promise<boolean> {
    if (!this.transport) return false;
    try {
      await this.transport.verify();
      this.recordSuccess();
      return true;
    } catch {
      this.recordFailure();
      return false;
    }
  }

  // ----------------------------------------------------------------
  // Internal
  // ----------------------------------------------------------------
  private formatAddress(addr: IMailAddress): string {
    if (addr.name) {
      return `${addr.name} <${addr.email}>`;
    }
    return addr.email;
  }

  private mapAttachments(attachments: Partial<IAttachment>[]): nodemailer.Attachment[] {
    return attachments
      .filter((a) => a.content) // only valid attachments
      .map((a) => ({
        filename: a.filename || 'attachment',
        contentType: a.mimeType,
        content: a.content as Buffer,
        disposition: a.disposition || 'attachment',
        contentId: a.contentId,
      })) as nodemailer.Attachment[];
  }

  private ensureReady(): void {
    if (!this.ready || !this.transport) {
      throw new CruxError('SMTP_NOT_CONNECTED', 'SMTP adapter not connected');

