  await notificationQueue?.close();
  
  imapSyncQueue = null;
  emailSendQueue = null;
  pgpProcessQueue = null;
  clamavScanQueue = null;
  notificationQueue = null;

  auditLogger.info('All BullMQ queues closed');
}

