    });

    // Replace body with encrypted content
    const encryptedOptions: SendEmailOptions = {
      ...options,
      text: typeof encryptedText === 'string' ? encryptedText : encryptedText.toString(),
      html: undefined, // No HTML for encrypted messages
    };

