function stemWord(word: string): string {
  if (word.length <= 3) return word.toLowerCase();
  let result = word.toLowerCase();
  for (const [pattern, replacement] of STEM_RULES) {
    result = result.replace(pattern, replacement as string);
  }
  return result;
}

